func (o *OrmStub) FilterChain(next orm.Filter) orm.Filter {
	return func(ctx context.Context, inv *orm.Invocation) []interface{} {
		ms := mockFromCtx(ctx)
		ms = append(ms, o.ms...)

		for _, mock := range ms {
			if mock.cond.Match(ctx, inv) {
				if mock.cb != nil {
					mock.cb(inv)
				}
				return mock.resp
			}
		}
		return next(ctx, inv)
	}
}
